            $bchfZnGQPHtFZCnnfFHVfLCcdBBzWXxZLeBVLdtP = Get-SQLDomainObject -Verbose -Instance $Instance -RtJukvwKfwOlPQngqWVpGHVGe $RtJukvwKfwOlPQngqWVpGHVGe -vHUDlofUDQptxSqQlxBWneRjFFhcpjPC $vHUDlofUDQptxSqQlxBWneRjFFhcpjPC -kBZWVgDkSbarPBJtRXobfjtpvvfbLJRETAA $kBZWVgDkSbarPBJtRXobfjtpvvfbLJRETAA -fmedDVMwwOoqfdIEgdaUOcFLJT $fmedDVMwwOoqfdIEgdaUOcFLJT -HPARjgzOnApTYHwzaBmwCfSJ $iuHygPCiBvXLHUbYBxujICnhUZftkaeCErinvaXggfH -GJvlkRgBjRXkfUSqMStHS "(objectClass=trustedDomain)" -NibxjztOIGfQbBuZlMtYJTqqqiCKfkDFpmqbElEGfG 'trustpartner,distinguishedname,trusttype,trustdirection,trustattributes,whencreated,whenchanged,adspath' -rLWesasRpKpmMqxSdOJA            
        }else{
            $bchfZnGQPHtFZCnnfFHVfLCcdBBzWXxZLeBVLdtP = Get-SQLDomainObject -Verbose -Instance $Instance -RtJukvwKfwOlPQngqWVpGHVGe $RtJukvwKfwOlPQngqWVpGHVGe -vHUDlofUDQptxSqQlxBWneRjFFhcpjPC $vHUDlofUDQptxSqQlxBWneRjFFhcpjPC -kBZWVgDkSbarPBJtRXobfjtpvvfbLJRETAA $kBZWVgDkSbarPBJtRXobfjtpvvfbLJRETAA -fmedDVMwwOoqfdIEgdaUOcFLJT $fmedDVMwwOoqfdIEgdaUOcFLJT -HPARjgzOnApTYHwzaBmwCfSJ $iuHygPCiBvXLHUbYBxujICnhUZftkaeCErinvaXggfH -GJvlkRgBjRXkfUSqMStHS "(objectClass=trustedDomain)" -NibxjztOIGfQbBuZlMtYJTqqqiCKfkDFpmqbElEGfG 'trustpartner,distinguishedname,trusttype,trustdirection,trustattributes,whencreated,whenchanged,adspath'            
