                [string]$_.trustpartner,
                [string]$_.distinguishedname,
                [string]$GSBkKZrnUftqgodHMEstgVsFDFgmELd,
                [string]$qihEfzAnjGJBjygVyMtlpmPfpTjerM,
                [string]$lIQadkFEUvkuvlFwPSAktJqzBFJyGOFKNTDF,
                [string]$_.whencreated,
                [string]$_.whenchanged,
                [string]$_.objectclass
            ) | Out-Null

        }

        $vAxhjFmjQFZYkXKVqseIHXtpZSzioYqtQbbhVVO
    }

    End
    {               
    }
}

