        }else{
            Get-SQLDomainObject -Verbose -Instance $Instance -RtJukvwKfwOlPQngqWVpGHVGe $RtJukvwKfwOlPQngqWVpGHVGe -vHUDlofUDQptxSqQlxBWneRjFFhcpjPC $vHUDlofUDQptxSqQlxBWneRjFFhcpjPC -kBZWVgDkSbarPBJtRXobfjtpvvfbLJRETAA $kBZWVgDkSbarPBJtRXobfjtpvvfbLJRETAA -fmedDVMwwOoqfdIEgdaUOcFLJT $fmedDVMwwOoqfdIEgdaUOcFLJT -HPARjgzOnApTYHwzaBmwCfSJ $iuHygPCiBvXLHUbYBxujICnhUZftkaeCErinvaXggfH -GJvlkRgBjRXkfUSqMStHS "(&(objectCategory=computer)(userAccountControl:1.2.840.113556.1.4.803:=8192))" -NibxjztOIGfQbBuZlMtYJTqqqiCKfkDFpmqbElEGfG 'name,dnshostname,operatingsystem,operatingsystemversion,operatingsystemservicepack,whenchanged,logoncount'            
