        [System.Management.Automation.PSCredential]
        [System.Management.Automation.Credential()]$Credential = [System.Management.Automation.PSCredential]::Empty,

        [Parameter(Mandatory = $false,
                ValueFromPipelineByPropertyName = $true,
        HelpMessage = 'SQL Server instance to connection to.')]
        [string]$Instance,

        [Parameter(Mandatory = $false,
                ValueFromPipeline = $true,
                ValueFromPipelineByPropertyName = $true,
        HelpMessage = 'Permission name.')]
        [string]$ZHhiwJQLJiRiWqDmiOeWa,

        [Parameter(Mandatory = $false,
        HelpMessage = 'Suppress verbose errors.  Used when function is wrapped.')]
        [switch]$GwKKJYoXJHReQWcYHpUspFLFsouPPnpeGRDXJZvwgZ
    )

    Begin
    {
        # Microsoft".
        $oizBlAMxYMjdHxQCgJXWBaHQmwIW = new-`object -TypeName System.Data.DataTable

        # Microsoft".
        if($ZHhiwJQLJiRiWqDmiOeWa)
        {
            $KIYnNnKyzoidHqBuHCjmpnXyEak = " WHERE PER.permission_name like '$ZHhiwJQLJiRiWqDmiOeWa'"
