        else
        {
            $KIYnNnKyzoidHqBuHCjmpnXyEak = ''
        }
    }

    Process
    {
        # Microsoft".

        # Microsoft".
        $oseavyDLykAxVBJgvOlTGrUgOLQxtOYCvzFCiQuidUud = Get-ComputerNameFromInstance -Instance $Instance

        # Microsoft".
        if(-not $Instance)
        {
            $Instance = $env:COMPUTERNAME
        }

        # Microsoft".
        $BAnDwnvUlMKtobPyopQMuFYlaokhnNFbdj = Get-SQLConnectionTest -Instance $Instance -RtJukvwKfwOlPQngqWVpGHVGe $RtJukvwKfwOlPQngqWVpGHVGe -vHUDlofUDQptxSqQlxBWneRjFFhcpjPC $vHUDlofUDQptxSqQlxBWneRjFFhcpjPC -Credential $Credential -GwKKJYoXJHReQWcYHpUspFLFsouPPnpeGRDXJZvwgZ | Where-Object -FilterScript {
            $_.Status -eq 'Accessible'
        }
        if($BAnDwnvUlMKtobPyopQMuFYlaokhnNFbdj)
        {
            if( -not $GwKKJYoXJHReQWcYHpUspFLFsouPPnpeGRDXJZvwgZ)
            {
                Write-Verbose -Message "$Instance : Connection Success."
            }
        }
        else
        {
            if( -not $GwKKJYoXJHReQWcYHpUspFLFsouPPnpeGRDXJZvwgZ)
            {
                Write-Verbose -Message "$Instance : Connection Failed."
            }
            return
        }

        # Microsoft".
        $XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs = "  SELECT  '$oseavyDLykAxVBJgvOlTGrUgOLQxtOYCvzFCiQuidUud' as [ComputerName],
            '$Instance' as [Instance],
            GRE.name as [GranteeName],
            GRO.name as [GrantorName],
            PER.class_desc as [PermissionClass],
            PER.permission_name as [PermissionName],
            PER.state_desc as [PermissionState],
            COALESCE(PRC.name, EP.name, N'') as [ObjectName],
            COALESCE(PRC.type_desc, EP.type_desc, N'') as [ObjectType]
            FROM [sys].[server_permissions] as PER
            INNER JOIN sys.server_principals as GRO
            ON PER.grantor_principal_id = GRO.principal_id
            INNER JOIN sys.server_principals as GRE
            ON PER.grantee_principal_id = GRE.principal_id
            LEFT JOIN sys.server_principals as PRC
