        $yaIWtyVSlGvGFINsTKXLsJZibCNbkSzsz = Get-SQLQuery -Instance $Instance -XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs $XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs -RtJukvwKfwOlPQngqWVpGHVGe $RtJukvwKfwOlPQngqWVpGHVGe -vHUDlofUDQptxSqQlxBWneRjFFhcpjPC $vHUDlofUDQptxSqQlxBWneRjFFhcpjPC -Credential $Credential -GwKKJYoXJHReQWcYHpUspFLFsouPPnpeGRDXJZvwgZ

