        if($WeDslRtslPeeQnDrqHeF){
            $bWglIfbwJPWyqLqMIyqLQgKHTGOOqhoseGISrkCifs = "WHERE af.name LIKE '%$WeDslRtslPeeQnDrqHeF%'"
        }else{
            $bWglIfbwJPWyqLqMIyqLQgKHTGOOqhoseGISrkCifs = ""
        }

