                $MHaqudWOQjtCHVVfzSeLCbxlHtfcolgSJydEOu = $_.assembly_name
                $qSuWwWBiyJLeJUHSiETKTwvYK = $_.assembly_class
                $PbhFypvJLKSiGHtzGZeozVNPvEXwkJaMtGKzumllJp = $_.sp_name   
                
                # Microsoft".
