            $UgViiVJVcVXEzCUEInKBMm.Links = [array]$hfzoabdgRnPYEZisGWnb.srvname

            if($XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs -ne ""){
                if($FRtljslpKlcoGzpQpFyimaxsuGitgyMTlQH -eq "" -or ($FRtljslpKlcoGzpQpFyimaxsuGitgyMTlQH -ne "" -and $UgViiVJVcVXEzCUEInKBMm.Instance -eq $FRtljslpKlcoGzpQpFyimaxsuGitgyMTlQH)){
                    if($XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs -like '*xp_cmdshell*'){
