                    $hfzoabdgRnPYEZisGWnb = Get-SqlQuery -instance $Instance -XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs ((Get-SQLServerLinkQuery -path $UgViiVJVcVXEzCUEInKBMm.Path -XEBBGqgYXDfGEKsMEbIbQfUSQzvoCeuGUFnSk $XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs)) -GeEChqOCvOrGzztnEvCZAibzuTX $GeEChqOCvOrGzztnEvCZAibzuTX -RtJukvwKfwOlPQngqWVpGHVGe $RtJukvwKfwOlPQngqWVpGHVGe -vHUDlofUDQptxSqQlxBWneRjFFhcpjPC $vHUDlofUDQptxSqQlxBWneRjFFhcpjPC -Credential $Credential
                    if($XrKWeKECrYdpWtWaZksfDhdaiGdICyjvKeBRSUYJxEs -like '*WITH RESULT SETS*'){
