Function Get-SQLServerLinkQuery{
    [CmdletBinding()]
    Param(
        [Parameter(Mandatory=$false,
        HelpMessage="SQL link path to crawl. This is used by Get-SQLServerLinkCrawl.")]
        $Path=@(),
        
        [Parameter(Mandatory=$false,
        HelpMessage="SQL query to build the crawl path around")]
        $XEBBGqgYXDfGEKsMEbIbQfUSQzvoCeuGUFnSk, 
        
        [Parameter(Mandatory=$false,
        HelpMessage="Counter to determine how many single quotes needed")]
        $dhwAHWkVXsAsAtxXPqexXcgJ=0

    )
    if ($Path.length -le 1){
        return($XEBBGqgYXDfGEKsMEbIbQfUSQzvoCeuGUFnSk -replace "'", ("'"*[Math]::pow(2,$dhwAHWkVXsAsAtxXPqexXcgJ)))
    } else {
        return("select * from openquery(`""+$Path[1]+"`","+"'"*[Math]::pow(2,$dhwAHWkVXsAsAtxXPqexXcgJ)+
        (Get-SQLServerLinkQuery -path $Path[1..($Path.Length-1)] -XEBBGqgYXDfGEKsMEbIbQfUSQzvoCeuGUFnSk $XEBBGqgYXDfGEKsMEbIbQfUSQzvoCeuGUFnSk -dhwAHWkVXsAsAtxXPqexXcgJ ($dhwAHWkVXsAsAtxXPqexXcgJ+1))+"'"*[Math]::pow(2,$dhwAHWkVXsAsAtxXPqexXcgJ)+")")
    }
}


